import{_ as o,o as e,c as p,a2 as r}from"./chunks/framework.Bix3-HpO.js";const l=JSON.parse('{"title":"AMP Support","description":"Spinoko Theme AMP Support","frontmatter":{"title":"AMP Support","description":"Spinoko Theme AMP Support","weight":180,"extra":{"order":180},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/amp"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/amp"}],["meta",{"property":"og:title","content":"AMP Support"}],["meta",{"property":"og:description","content":"Spinoko Theme AMP Support"}],["meta",{"name":"twitter:title","content":"AMP Support"}],["meta",{"name":"twitter:description","content":"Spinoko Theme AMP Support"}]]},"headers":[],"relativePath":"docs/spinoko/amp.md","filePath":"docs/spinoko/amp.md"}'),a={name:"docs/spinoko/amp.md"};function i(n,t,s,c,m,d){return e(),p("div",null,[...t[0]||(t[0]=[r('<h1 id="amp-support" tabindex="-1">AMP Support <a class="header-anchor" href="#amp-support" aria-label="Permalink to &quot;AMP Support&quot;">​</a></h1><p>Spinoko comes with built-in AMP support.</p><hr><p>Spinoko supports AMP functionality out of the box. All you have to do is just install the <strong>official AMP plugin for WordPress</strong> and activate it.</p><p>Here&#39;s the AMP Plugin settings page:</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-amp.png" alt="spinoko-amp-support"></p><p>You can get the plugin from WordPress Plugins Directory: <a href="https://wordpress.org/plugins/amp/" target="_blank" rel="noreferrer">AMP By AMP Project Contributors</a> or add it through your WordPress dashboard Plugins page.</p><p>To check the AMP functionality of the theme, simply append ?amp to the page URLs.</p>',8)])])}const h=o(a,[["render",i]]);export{l as __pageData,h as default};
